import "../quiz_question.dart";

const _subject = "English Language";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// WAEC Structure: word classes, tenses and concord, sentences and clauses,
/// voice and speech, and punctuation — the grammar half of the Lexis and
/// Structure paper.
