    ..._adjectives,
    ..._adverbs,
    ..._prepositions,
    ..._conjunctions,
    ..._interjections,
    ..._tense,
    ..._concord,
    ..._nounClauses,
    ..._adjectivalClauses,
    ..._adverbialClauses,
    ..._activePassive,
    ..._directIndirect,
    ..._punctuation,
  ];
}

